type
  TRectangle = record
    width, height: Integer;
  end;

function Area(r: TRectangle): Integer;
begin
  Area := r.width * r.height;
end;

var
  rect: TRectangle;
begin
  rect.width := 4;
  rect.height := 5;
  writeln(Area(rect));
end.

